package main

import "fmt"

func gcd(a int, b int) int {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func lcm(a int, b int) int {
	return (a * b) / gcd(a, b)
}

func main() {
	num1, num2 := 48, 18

	fmt.Println("Sayilar:", num1, "ve", num2)
	fmt.Println("EBOB (GCD):", gcd(num1, num2))
	fmt.Println("EKOK (LCM):", lcm(num1, num2))

	// Birden fazla cift icin tablo
	fmt.Println("\nFarkli sayi ciftleri:")
	pairs := [][2]int{{12, 18}, {7, 13}, {100, 75}, {24, 36}}

	for _, pair := range pairs {
		a, b := pair[0], pair[1]
		fmt.Printf("GCD(%d,%d) = %d, LCM(%d,%d) = %d\n", a, b, gcd(a, b), a, b, lcm(a, b))
	}
}
